    "status": "Activo",
    "published": "2026-05-16T11:17:17.983Z",
    "content": "<div style=\"background: linear-gradient(135deg, #0284c7 0%, #2563eb 100%); padding: 12px 20px; border-radius: 12px; color: white; display: flex; align-items: center; justify-content: space-between; margin-bottom: 20px; box-shadow: 0 4px 15px rgba(37, 99, 235, 0.15);\">\n    <div style=\"display: flex; align-items: center; gap: 15px;\">\n        <span style=\"font-size: 1.8rem;\">🌍</span>\n        <h1 style=\"margin: 0; font-size: 1.4rem; font-weight: 800; letter-spacing: -0.5px;\">Canales Online</h1>\n    </div>\n    <div style=\"display: inline-flex; align-items: center; gap: 8px; background: rgba(255,255,255,0.15); padding: 4px 12px; border-radius: 20px; border: 1px solid rgba(255,255,255,0.25);\">\n        <span style=\"display: inline-block; width: 6px; height: 6px; background: #67e8f9; border-radius: 50%;\"></span>\n        <span style=\"font-size: 0.7rem; font-weight: 800; text-transform: uppercase; letter-spacing: 1px; color: #e0f2fe;\">Módulo Operativo</span>\n    </div>\n</div>\n\n{{CHANNELS_EXPLORER}}",
    "isCritical": false,
