    "updated": "2026-06-18T01:59:12.444Z",
    "content": "<div class=\"page-wrapper\">\n        <div class=\"bg-pattern\"></div>\n\n        <main class=\"main-content\">\n            <!-- Icono de Calidad / Sello -->\n            <div class=\"mb-10 animate-subtle-float\">\n                <div class=\"brand-seal w-20 h-20 md:w-24 md:h-24 rounded-2xl flex items-center justify-center\">\n                    <svg class=\"w-10 h-10 md:w-12 md:h-12 text-white\" fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\">\n                        <path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"1.5\" d=\"M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z\" />\n                    </svg>\n                </div>\n            </div>\n\n            <!-- Identidad -->\n            <div class=\"mb-6 space-y-2\">\n                <span class=\"text-[11px] font-bold text-[#A58C5F] uppercase tracking-[0.4em]\">Estándares de Calidad</span>\n                <h2 class=\"text-xl md:text-2xl font-medium text-slate-400\">\n                    Sercotel Guadiana <span class=\"mx-1 text-slate-300\">|</span> Cumbria Spa & Hotel\n                </h2>\n            </div>\n\n            <!-- Mensaje Central -->\n            <div class=\"max-w-3xl mx-auto px-4 mb-10\">\n                <h1 class=\"text-4xl md:text-6xl font-extrabold tracking-tight mb-6 text-gradient\">\n                    Sección en Fase de <br> Mejora Continua\n                </h1>\n                <p class=\"text-slate-500 text-base md:text-lg font-normal max-w-xl mx-auto leading-relaxed\">\n                    Estamos actualizando nuestros protocolos operativos para alinearlos con los más altos niveles de excelencia en el servicio de recepción.\n                </p>\n            </div>\n\n            <!-- Indicador de Estado -->\n            <div class=\"w-full max-w-md px-6 mb-12\">\n                <div class=\"flex justify-between items-end mb-3\">\n                    <div class=\"text-left\">\n                        <p class=\"text-[10px] font-bold text-slate-400 uppercase tracking-widest\">Estado del proyecto</p>\n                        <p class=\"text-sm font-semibold text-slate-700\">Implementación de procesos</p>\n                    </div>\n                    <span class=\"text-xs font-bold text-[#A58C5F]\">75%</span>\n                </div>\n                <div class=\"progress-track\">\n                    <div class=\"progress-bar\"></div>\n                </div>\n            </div>\n\n            <!-- Navegación -->\n            <div class=\"flex flex-col sm:flex-row items-center justify-center gap-4 w-full px-6\">\n                <a href=\"https://cumbriaspahotel.github.io/Protocolo-Recep/\" \n                   class=\"nav-button-primary w-full sm:w-auto px-10 py-4 text-white rounded-xl font-bold flex items-center justify-center gap-3\">\n                    <svg class=\"w-5 h-5\" fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6\"/></svg>\n                    Volver a Inicio\n                </a>\n                <button onclick=\"history.back()\" \n                        class=\"w-full sm:w-auto px-10 py-4 bg-white text-slate-600 border border-slate-200 rounded-xl font-bold hover:bg-slate-50 hover:border-slate-300 transition-all\">\n                    Página anterior\n                </button>\n            </div>\n        </main>\n\n        <!-- Pie de Página Profesional -->\n        <footer class=\"footer\">\n            <div class=\"max-w-4xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4\">\n                <p class=\"text-[11px] text-slate-400 font-semibold uppercase tracking-[0.2em]\">\n                    Sercotel Guadiana <span class=\"mx-2 text-[#A58C5F]\">•</span> Cumbria Spa & Hotel\n                </p>\n                <div class=\"flex items-center gap-4\">\n                    <span class=\"h-px w-8 bg-slate-100 hidden md:block\"></span>\n                    <p class=\"text-[10px] text-slate-500 font-bold uppercase tracking-widest\">\n                        Departamento de Recepción\n                    </p>\n                </div>\n            </div>\n        </footer>\n    </div>",
