    "title": "🛏️ Asignación de habitaciones",
    "section": "2.1.5",
    "source": "Ambos hoteles",
    "published": "2026-05-23T20:45:56.357Z",
    "updated": "2026-05-25T13:13:35.471Z",
    "content": "<div class=\"page-wrapper\" style=\"min-height: 100vh; background: #f8fafc; font-family: 'Outfit', 'Segoe UI', sans-serif; display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 2rem; box-sizing: border-box;\">\n    <!-- Estilos CSS integrados -->\n    <style>\n        .brand-seal { background: linear-gradient(135deg, #A58C5F 0%, #8b7348 100%); box-shadow: 0 10px 25px -5px rgba(165, 140, 95, 0.3); }\n        .text-gradient { background: linear-gradient(to right, #1e293b, #475569); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }\n        .progress-track { width: 100%; height: 8px; background: #e2e8f0; border-radius: 9999px; overflow: hidden; }\n        .progress-bar { width: 75%; height: 100%; background: #A58C5F; border-radius: 9999px; }\n        .nav-button-primary { background: linear-gradient(135deg, #1e293b 0%, #334155 100%); box-shadow: 0 4px 12px rgba(30, 41, 59, 0.2); transition: transform 0.2s; }\n        .nav-button-primary:hover { transform: translateY(-2px); }\n        .footer { margin-top: auto; padding: 3rem 0; width: 100%; text-align: center; border-top: 1px solid #e2e8f0; }\n    </style>\n\n    <main class=\"main-content\" style=\"width: 100%; max-width: 800px; text-align: center; margin-bottom: 4rem;\">\n        <!-- Icono de Calidad / Sello -->\n        <div class=\"mb-10\" style=\"margin-bottom: 2.5rem; display: flex; justify-content: center;\">\n            <div class=\"brand-seal\" style=\"width: 80px; height: 80px; border-radius: 16px; display: flex; align-items: center; justify-content: center;\">\n                <svg class=\"w-12 h-12 text-white\" fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\" style=\"width: 40px; height: 40px;\">\n                    <path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"1.5\" d=\"M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z\" />\n                </svg>\n            </div>\n        </div>\n\n        <!-- Identidad -->\n        <div class=\"mb-6\" style=\"margin-bottom: 1.5rem;\">\n            <span style=\"font-size: 11px; font-weight: 800; color: #A58C5F; text-transform: uppercase; letter-spacing: 0.4em;\">Estándares de Calidad</span>\n            <h2 style=\"font-size: 1.5rem; font-weight: 500; color: #94a3b8; margin: 0.5rem 0;\">\n                Sercotel Guadiana <span style=\"margin: 0 0.5rem; color: #cbd5e1;\">|</span> Cumbria Spa & Hotel\n            </h2>\n        </div>\n\n        <!-- Mensaje Central -->\n        <div style=\"max-width: 600px; margin: 0 auto 2.5rem auto; padding: 0 1rem;\">\n            <h1 style=\"font-size: 3rem; font-weight: 800; letter-spacing: -0.02em; margin-bottom: 1.5rem;\" class=\"text-gradient\">\n                Asignación de <br> Habitaciones\n            </h1>\n            <p style=\"color: #64748b; font-size: 1.125rem; line-height: 1.7;\">\n                Estamos actualizando nuestros protocolos operativos para alinearlos con los más altos niveles de excelencia en el servicio de recepción.\n            </p>\n        </div>\n\n        <!-- Indicador de Estado -->\n        <div style=\"width: 100%; max-width: 400px; margin: 0 auto 3rem auto; padding: 0 1.5rem;\">\n            <div style=\"display: flex; justify-content: space-between; align-items: flex-end; margin-bottom: 0.75rem;\">\n                <div style=\"text-align: left;\">\n                    <p style=\"font-size: 10px; font-weight: 800; color: #94a3b8; text-transform: uppercase; letter-spacing: 0.1em; margin: 0;\">Estado del proyecto</p>\n                    <p style=\"font-size: 0.875rem; font-weight: 600; color: #334155; margin: 0;\">Implementación de procesos</p>\n                </div>\n                <span style=\"font-size: 0.75rem; font-weight: 800; color: #A58C5F;\">75%</span>\n            </div>\n            <div class=\"progress-track\">\n                <div class=\"progress-bar\"></div>\n            </div>\n        </div>\n\n        <!-- Navegación -->\n        <div style=\"display: flex; flex-direction: column; sm:flex-row; align-items: center; justify-content: center; gap: 1rem; padding: 0 1.5rem;\">\n            <a href=\"https://cumbriaspahotel.github.io/Protocolo-Recep/\" class=\"nav-button-primary\" style=\"width: 100%; max-width: 250px; padding: 1rem; color: white; border-radius: 12px; font-weight: 700; text-decoration: none; display: flex; align-items: center; justify-content: center; gap: 10px;\">\n                <svg class=\"w-5 h-5\" fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\" style=\"width: 20px; height: 20px;\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6\"/></svg>\n                Volver a Inicio\n            </a>\n            <button onclick=\"history.back()\" style=\"width: 100%; max-width: 250px; padding: 1rem; background: white; color: #475569; border: 1px solid #e2e8f0; border-radius: 12px; font-weight: 700; cursor: pointer; transition: all 0.2s;\">\n                Página anterior\n            </button>\n        </div>\n    </main>\n\n    <!-- Pie de Página -->\n    <footer class=\"footer\">\n        <div style=\"max-width: 800px; margin: 0 auto; display: flex; flex-direction: column; align-items: center; gap: 1rem;\">\n            <p style=\"font-size: 11px; color: #94a3b8; font-weight: 600; text-transform: uppercase; letter-spacing: 0.2em; margin: 0;\">\n                Sercotel Guadiana <span style=\"margin: 0 0.5rem; color: #A58C5F;\">•</span> Cumbria Spa & Hotel\n            </p>\n            <p style=\"font-size: 10px; color: #64748b; font-weight: 700; text-transform: uppercase; letter-spacing: 0.1em; margin: 0;\">\n                Departamento de Recepción\n            </p>\n        </div>\n    </footer>\n</div>",
